output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?game ?duration WHERE {
  {
    ?event wdt:P31 wd:Q1463 ; rdfs:label ?eventLabel ; wdt:P585 ?eventDate .
    FILTER(LANG(?eventLabel) = "en")
    .
    FILTER(CONTAINS(LCASE(?eventLabel) , "national league championship series"))
    .
    FILTER(STRSTARTS(STR(?eventDate) , "1982") || STRSTARTS(STR(?eventDate) , "2006") || STRSTARTS(STR(?eventDate) , "2011") || STRSTARTS(STR(?eventDate) , "2013"))
  } UNION {
    ?event wdt:P31 wd:Q52342 ; rdfs:label ?eventLabel ; wdt:P585 ?eventDate .
    FILTER(LANG(?eventLabel) = "en")
    .
    FILTER(CONTAINS(LCASE(?eventLabel) , "world series"))
    .
    FILTER(STRSTARTS(STR(?eventDate) , "2011"))
  }
  ?game wdt:P135 ?event .
  {
    ?game wdt:P170 wd:Q31127
  } UNION {
    ?game wdt:P171 wd:Q31127
  }
  .
  ?game wdt:P2683 ?duration .
}
ORDER BY DESC(?duration)
LIMIT 1

